/**
 * Parses a duration string into milliseconds. The string must consist of a positive number
 * (integer or decimal) followed by a unit: 'ms' (milliseconds), 's' (seconds), 'm' (minutes),
 * 'h' (hours), or 'd' (days). The input is trimmed before parsing, and the result is rounded
 * to the nearest integer.
 *
 * @param {string} str - The duration string to parse.
 * @returns {number} The parsed duration in milliseconds as an integer.
 * @throws {Error} If the duration string does not match the expected format.
 * @example
 * parseDuration("2.5h"); // returns 9000000 (which is 2.5 hours in milliseconds)
 */
function parseDuration(str) {
  const m = /^(\d+(?:\.\d+)?)(ms|s|m|h|d)$/.exec(str.trim());
  if (!m) throw new Error('Invalid duration: ' + str);
  const n = parseFloat(m[1]);
  const u = m[2];
  const mult = { ms: 1, s: 1000, m: 60000, h: 3600000, d: 86400000 }[u];
  return Math.round(n * mult);
}
